/**
 * Netlify Function: /.netlify/functions/command-scorecards
 *
 * GET — returns the aggregated agent scorecards shipped with the site at
 *   data/scorecards.json (generated by scripts/sync-scorecards.js from the
 *   cornerstone-research-group repo).
 *
 * Shape returned:
 *   {
 *     backend: 'static',
 *     synced_at,
 *     count,
 *     agents: [ scorecard, ... ]   // agent_id, name, team, role, rubric_id,
 *                                  //   current_grade, trend, recent_evaluations,
 *                                  //   active_version, owner
 *   }
 *
 * Falls back to an empty array with backend='missing' if the file isn't
 * deployed — UI shows an empty state rather than 500ing.
 */

const fs = require('fs');
const path = require('path');
const { checkAuth, unauthorized } = require('./_lib/garvis-auth');

function cors() {
  return {
    'Access-Control-Allow-Origin': '*',
    'Access-Control-Allow-Methods': 'GET, OPTIONS',
    'Access-Control-Allow-Headers': 'Content-Type',
    'Content-Type': 'application/json',
    'Cache-Control': 'no-store'
  };
}

// Candidate paths — at runtime Netlify Functions run from .netlify/functions
// with publish dir bundled alongside. Try a few likely locations.
const CANDIDATES = [
  path.resolve(__dirname, '..', '..', 'data', 'scorecards.json'),
  path.resolve(process.cwd(), 'data', 'scorecards.json'),
  path.resolve(__dirname, '..', '..', '..', 'data', 'scorecards.json')
];

function readScorecards() {
  for (const p of CANDIDATES) {
    try {
      if (fs.existsSync(p)) {
        const raw = fs.readFileSync(p, 'utf8');
        return { ok: true, data: JSON.parse(raw), path: p };
      }
    } catch (_) {
      /* try next */
    }
  }
  return { ok: false };
}

exports.handler = async function (event) {
  if (event.httpMethod === 'OPTIONS') {
    return { statusCode: 200, headers: cors(), body: '' };
  }
  if (event.httpMethod !== 'GET') {
    return {
      statusCode: 405,
      headers: cors(),
      body: JSON.stringify({ error: 'method_not_allowed' })
    };
  }
  if (!checkAuth(event)) return unauthorized(cors());

  const result = readScorecards();
  if (!result.ok) {
    return {
      statusCode: 200,
      headers: cors(),
      body: JSON.stringify({
        backend: 'missing',
        synced_at: null,
        count: 0,
        agents: [],
        note: 'data/scorecards.json not bundled — run scripts/sync-scorecards.js'
      })
    };
  }

  const payload = result.data || {};
  const agents = Array.isArray(payload.scorecards) ? payload.scorecards : [];

  // Sort by current_grade desc, then name
  const sorted = [...agents].sort((a, b) => {
    const ga = Number(a.current_grade) || 0;
    const gb = Number(b.current_grade) || 0;
    if (ga !== gb) return gb - ga;
    return (a.name || '').localeCompare(b.name || '');
  });

  return {
    statusCode: 200,
    headers: cors(),
    body: JSON.stringify({
      backend: 'static',
      synced_at: payload.synced_at || null,
      count: sorted.length,
      agents: sorted,
      timestamp: new Date().toISOString()
    })
  };
};
